namespace BlazorApp.Services;

public record Notification(int Id, string Message, DateTime Timestamp);

public class NotificationService
{
    private int _nextId = 4;
    private readonly Lock _lock = new();
    private readonly List<Notification> _notifications =
    [
        new(1, "Welcome to the app!", DateTime.UtcNow.AddMinutes(-30)),
        new(2, "Your profile was updated.", DateTime.UtcNow.AddMinutes(-15)),
        new(3, "New feature available: Dark Mode.", DateTime.UtcNow.AddMinutes(-5)),
    ];

    private static readonly string[] SampleMessages =
    [
        "Deployment completed successfully.",
        "New comment on your post.",
        "Scheduled maintenance tonight at 11 PM.",
        "Your report is ready to download.",
        "A new user joined your team.",
        "Password change reminder.",
        "Server health check passed.",
    ];

    public Task<List<Notification>> GetNotificationsAsync()
    {
        lock (_lock)
        {
            return Task.FromResult(_notifications.OrderByDescending(n => n.Timestamp).ToList());
        }
    }

    /// <summary>
    /// Returns any notifications added after the given timestamp.
    /// Randomly adds 0-1 new notifications each time it's called to simulate activity.
    /// </summary>
    public Task<List<Notification>> GetNotificationsSinceAsync(DateTime since)
    {
        lock (_lock)
        {
            if (Random.Shared.Next(3) == 0) // ~33% chance of a new notification
            {
                var msg = SampleMessages[Random.Shared.Next(SampleMessages.Length)];
                _notifications.Add(new Notification(_nextId++, msg, DateTime.UtcNow));
            }

            return Task.FromResult(
                _notifications
                    .Where(n => n.Timestamp > since)
                    .OrderByDescending(n => n.Timestamp)
                    .ToList());
        }
    }
}

@page "/notifications"
@rendermode InteractiveServer
@using BlazorApp.Services
@inject NotificationService NotificationService
@implements IAsyncDisposable

<PageTitle>Notifications</PageTitle>

<h1>
    Notifications
    @if (notifications is not null)
    {
        <span class="badge bg-primary rounded-pill ms-2">@notifications.Count</span>
    }
</h1>

@if (notifications is null)
{
    <p><em>Loading...</em></p>
}
else if (notifications.Count == 0)
{
    <p>No notifications.</p>
}
else
{
    <ul class="list-group">
        @foreach (var n in notifications)
        {
            <li class="list-group-item d-flex justify-content-between align-items-start">
                <div>@n.Message</div>
                <small class="text-muted">@n.Timestamp.ToString("HH:mm:ss")</small>
            </li>
        }
    </ul>
}

@code {
    [PersistentState]
    public List<Notification>? notifications { get; set; }

    private DateTime lastCheck;
    private CancellationTokenSource? cts;

    protected override async Task OnInitializedAsync()
    {
        // Only fetch if not already restored from prerender state
        notifications ??= await NotificationService.GetNotificationsAsync();
        lastCheck = notifications.Count > 0
            ? notifications.Max(n => n.Timestamp)
            : DateTime.UtcNow;
    }

    protected override void OnAfterRender(bool firstRender)
    {
        if (firstRender)
        {
            // Start polling only after the page is interactive (never during prerender)
            cts = new CancellationTokenSource();
            _ = PollForNotificationsAsync(cts.Token);
        }
    }

    private async Task PollForNotificationsAsync(CancellationToken token)
    {
        while (!token.IsCancellationRequested)
        {
            try
            {
                await Task.Delay(TimeSpan.FromSeconds(5), token);

                var newer = await NotificationService.GetNotificationsSinceAsync(lastCheck);
                if (newer.Count > 0)
                {
                    notifications = [..newer, ..notifications!];
                    lastCheck = notifications.Max(n => n.Timestamp);
                    await InvokeAsync(StateHasChanged);
                }
            }
            catch (TaskCanceledException)
            {
                break;
            }
        }
    }

    public async ValueTask DisposeAsync()
    {
        if (cts is not null)
        {
            await cts.CancelAsync();
            cts.Dispose();
        }
    }
}

